var data = [];
function originOf(url) {
  var match = String(url || "").match(/^(https?:\/\/[^\/]+)/i);
  return match ? match[1] : KETSU_BASE_URL;
}
function thumbnailOf(item) {
  var thumbs = item.thumbnails || [];
  for (var t = thumbs.length - 1; t >= 0; t--) if (thumbs[t].fileUrl) return thumbs[t].fileUrl;
  return absUrl(item.previewPath || item.thumbnailPath || "", KETSU_BASE_URL);
}
function channelName(item) {
  return (item.channel && (item.channel.displayName || item.channel.name)) || (item.account && (item.account.displayName || item.account.name)) || "PeerTube";
}
function durationLabel(seconds) {
  seconds = parseInt(seconds || 0, 10);
  if (!seconds) return "";
  var minutes = Math.floor(seconds / 60);
  var remain = seconds % 60;
  return minutes + ":" + (remain < 10 ? "0" : "") + remain;
}
