  var item = rows[i];
  if (!item.uuid || item.nsfw) continue;
  var origin = originOf(item.url);
  var link = origin + "/api/v1/videos/" + encodeURIComponent(item.uuid);
  var desc = item.description || item.truncatedDescription || "";
  var license = item.licence && item.licence.label ? item.licence.label : "";
  var host = (item.channel && item.channel.host) || (item.account && item.account.host) || origin.replace(/^https?:\/\//, "");
  data.push(pageData(link, thumbnailOf(item), item.name || "PeerTube Video", desc, durationLabel(item.duration), channelName(item), license || "Video", host));
}
emitPage("main", data, "PeerTube Anime");

